chapter.programlisting:
@Scenario("hello-world")
fun myScenario() {
    val myScenario = scenario {
        minionsCount = 1000
        profile {
            regular(1000, 50)
        }
    }
    myScenario.start() // Root branch receiving all minions.
        .returns<string>{ "My input" }
    myScenario // Second branch visited by a unique minion.
        .returns<String>{ "My other input" }
}

@Scenario("hello-world")
fun myScenario() {
    val myScenario = scenario {
    .start()
        .split {
             .map {
             .returns<String>{ "My other input"
             }
            flatten() {
                .filterNotNull()
            .returns<String>{ "My other input" }
            }
        }
    }
}
